class Solution {
public:
    int possibleStringCount(string word, int k) {
        int n = word.size();
        vector<int> groups;
        char prev = word[0];
        int count = 1;
        for (int i = 1; i < n; ++i) {
            if (word[i] == prev) {
                count++;
            } else {
                groups.push_back(count);
                count = 1;
                prev = word[i];
            }
        }
        groups.push_back(count);
        int m = groups.size();
        vector<vector<int>> dp(m + 1, vector<int>(k + 1, 0));
        dp[0][0] = 1;
        for (int i = 1; i <= m; ++i) {
            for (int j = 0; j <= k; ++j) {
                dp[i][j] = (dp[i][j] + dp[i - 1][j]) % (int)(1e9 + 7);
                if (j >= groups[i - 1] - 1 && j <= k - 1) {
                    dp[i][j] = (dp[i][j] + (long long)dp[i - 1][j - groups[i - 1] + 1] * (groups[i - 1] - 1)) % (int)(1e9 + 7);
                }
            }
        }
        return dp[m][k];
    }
};
